esqlQuery.esql:
FROM logs-*
// Restrict to Azure Activity Logs (Administrative category)
| WHERE azure.category IS NOT NULL
| WHERE azure.category == "Administrative"
// Mutations: write, delete, action operations (exclude read)
| WHERE azure.operation.name LIKE "*WRITE*" OR azure.operation.name LIKE "*DELETE*" OR azure.operation.name LIKE "*ACTION*"
// Exclude in-progress
| WHERE azure.result.type NOT IN ("Start", "Started")
// Derive actor for grouping
| EVAL actor = COALESCE(user.name, azure.identity.authorization.evidence.principal.id, "unknown")
// Aggregate mutation count by resource provider and actor — high counts indicate change storm
| STATS mutation_count = COUNT(*), operations = VALUES(azure.operation.name) BY azure.operation.name, actor
// Threshold: adjust based on normal baseline (e.g. 50+ mutations in 15m may indicate runaway automation)
| WHERE mutation_count >= 50
| SORT mutation_count DESC
| LIMIT 10
